export default (n) => {
  const seen = new Map();
  for (const p of n.view.plan ?? []) {
    const key = p.title ?? "(untitled)";
    if (!seen.has(key)) seen.set(key, p);
  }
  const plans = [...seen.values()].sort((a, b) => (a.when ?? 0) - (b.when ?? 0));
  const now = Date.now();
  const li = (p) => {
    const when = p.when ? new Date(p.when).toLocaleString() : "sometime";
    const past = (p.when ?? Infinity) < now;
    return `<li${past ? ' class="past"' : ""}><strong>${p.title ?? "(untitled)"}</strong> — ${when}${p.where ? ` @ ${p.where}` : ""}${p.rsvp?.length ? ` <em>(${p.rsvp.length} RSVP)</em>` : ""}</li>`;
  };
  return `<!doctype html><html><head><meta charset="utf-8"><title>Planner</title>
<style>body{font-family:system-ui;max-width:30rem;margin:2rem auto;padding:0 1rem}
h1{font-size:1.4rem}ul{list-style:none;padding:0}
li{padding:.5rem .6rem;border-bottom:1px solid #eee}.past{color:#aaa}</style></head><body>
<h1>Planner</h1><ul>${plans.map(li).join("")}</ul></body></html>`;
};
